INSERT INTO listings (category_id, slug, name, tagline, description, logo_url, website_url, affiliate_url, affiliate_commission, affiliate_details, pricing_type, starting_price, overall_rating, review_count, is_featured, is_verified, pros, cons) VALUES
(1, 'binance', 'Binance', 'The world''s largest crypto exchange', 'Binance is the world''s leading cryptocurrency exchange by trading volume, offering a robust platform for trading over 350 cryptocurrencies.', 'https://cryptologos.cc/logos/binance-coin-bnb-logo.png', 'https://binance.com', 'https://accounts.binance.com/en/register?ref=CRYPTO100', '20-40% trading fees', 'Earn up to 40% commission on trading fees from referrals. Tiered commission structure based on BNB holdings.', 'freemium', 'Free to start', 4.7, 12453, true, true, ARRAY['Largest selection of cryptocurrencies', 'Low trading fees', 'Advanced trading features', 'Binance Earn for passive income', 'Mobile app with trading'], ARRAY['Regulatory concerns in some countries', 'Can be overwhelming for beginners', 'Customer support response times']),
(1, 'coinbase', 'Coinbase', 'The easiest place to buy and sell crypto', 'Coinbase is the most trusted crypto exchange in the US, making it simple to buy, sell, and store cryptocurrency.', 'https://cryptologos.cc/logos/coinbase.png', 'https://coinbase.com', 'https://www.coinbase.com/join/YOUR_REFERRAL', '$10 per referral', 'Earn $10 for each friend who joins and trades $100 or more. Plus 50% of their trading fees for 3 months.', 'freemium', 'Free to start', 4.5, 8921, true, true, ARRAY['User-friendly interface', 'Insured custodial wallets', 'Regulated US exchange', 'Educational resources', 'Earn crypto while learning'], ARRAY['Higher fees than competitors', 'Limited altcoin selection', 'Account restrictions possible']),
(1, 'kraken', 'Kraken', 'Trade crypto with confidence', 'Kraken is a US-based cryptocurrency exchange offering secure trading with advanced features for experienced traders.', 'https://cryptologos.cc/logos/kraken.png', 'https://kraken.com', 'https://kraken.com/signup', '20% revenue share', 'Earn 20% of trading fees generated by your referrals for the life of their account.', 'freemium', 'Free to start', 4.6, 5632, true, true, ARRAY['Excellent security track record', 'Advanced trading tools', 'Margin and futures trading', 'Proof of reserves', '24/7 support'], ARRAY['Interface can be complex', 'Longer verification process', 'Limited payment methods']),
(1, 'bybit', 'Bybit', 'The crypto exchange of the future', 'Bybit is a derivatives-focused exchange offering ultra-fast execution and professional trading tools.', 'https://cryptologos.cc/logos/bit-logo.png', 'https://bybit.com', 'https://bybit.com/invite?ref=CryptoAff', 'Up to 50% commission', 'Earn up to 50% of trading fees with performance-based tiers. Plus new user sign-up bonuses up to $30,000.', 'freemium', 'Free to start', 4.5, 4521, false, true, ARRAY['Generous affiliate program', 'Derivatives specialist', 'Copy trading features', 'Trading competitions'], ARRAY['Not available in US', 'Complex fee structure', 'Customer support can be slow']),
(1, 'kucoin', 'KuCoin', 'People''s exchange for altcoins', 'KuCoin is known for listing the latest altcoins and offering a wide variety of trading pairs.', 'https://cryptologos.cc/logos/kucoin.png', 'https://kucoin.com', 'https://kucoin.com/u/signup?src=CryptoDir', '40% lifetime commission', 'Earn up to 40% lifetime commission on trading fees. Performance bonuses available for top affiliates.', 'freemium', 'Free to start', 4.3, 3892, false, true, ARRAY['Huge altcoin selection', 'KuCoin Earn products', 'Trading bot features', 'No KYC for withdrawals'], ARRAY['Less regulated', 'Security breach in 2020', 'Customer support delays']),
(1, 'gemini', 'Gemini', 'The trusted platform for crypto', 'Gemini is a New York trust company regulated by the NYSDFS, offering institutional-grade security.', 'https://cryptologos.cc/logos/gemini.png', 'https://gemini.com', 'https://gemini.com/share/YOUR_CODE', '$10 sign-up bonus', 'Earn $10 when your referral trades $100 within 30 days of signup.', 'freemium', 'Free to start', 4.4, 2341, false, true, ARRAY['US regulated exchange', 'Institutional trust', 'Gemini Earn interest', 'Simple interface'], ARRAY['Higher fees', 'Fewer altcoins', 'Limited international availability']);